import Foundation

// MARK: - Network Configuration

/// Custom URLSession delegate to handle SSL/TLS challenges for local IoT devices
class NetworkSessionDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate {
    
    /// Set of trusted local network prefixes
    private let trustedLocalPrefixes = [
        "192.168.",
        "10.",
        "172.16.", "172.17.", "172.18.", "172.19.",
        "172.20.", "172.21.", "172.22.", "172.23.",
        "172.24.", "172.25.", "172.26.", "172.27.",
        "172.28.", "172.29.", "172.30.", "172.31.",
        "localhost",
        "127.0.0.1"
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let host = challenge.protectionSpace.host as String?,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // Only allow insecure connections for local network devices
        let isLocalNetwork = trustedLocalPrefixes.contains { host.hasPrefix($0) }
        
        if isLocalNetwork {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            // For cloud API and other external hosts, use default SSL validation
            completionHandler(.performDefaultHandling, nil)
        }
    }
    
    func urlSession(
        _ session: URLSession,
        task: URLSessionTask,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        urlSession(session, didReceive: challenge, completionHandler: completionHandler)
    }
}

// MARK: - HTTP Method Enum

enum HTTPMethod: String {
    case GET
    case POST
    case PUT
    case PATCH
    case DELETE
}

// MARK: - Network Error

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case encodingError(Error)
    case httpError(statusCode: Int, data: Data?)
    case connectionFailed(Error)
    case timeout
    case unknown(Error)
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .encodingError(let error):
            return "Encoding error: \(error.localizedDescription)"
        case .httpError(let statusCode, _):
            return "HTTP error with status code: \(statusCode)"
        case .connectionFailed(let error):
            return "Connection failed: \(error.localizedDescription)"
        case .timeout:
            return "Request timed out"
        case .unknown(let error):
            return "Unknown error: \(error.localizedDescription)"
        }
    }
}

// MARK: - Network Response

struct NetworkResponse<T> {
    let data: T
    let statusCode: Int
    let headers: [AnyHashable: Any]
}

// MARK: - Endpoint Configuration

enum EndpointType {
    case cloudAPI
    case localDevice(ipAddress: String, port: Int?)
    
    var baseURL: String {
        switch self {
        case .cloudAPI:
            return "https://api.example.com"
        case .localDevice(let ip, let port):
            if let port = port {
                return "http://\(ip):\(port)"
            }
            return "http://\(ip)"
        }
    }
    
    var requiresAuth: Bool {
        switch self {
        case .cloudAPI:
            return true
        case .localDevice:
            return false
        }
    }
}

