        queryParameters: [String: String]?,
        timeoutInterval: TimeInterval
    ) async throws -> NetworkResponse<T>
    
    func requestRaw(
        endpoint: EndpointType,
        path: String,
        method: HTTPMethod,
        headers: [String: String]?,
