// MARK: - IoT Device Discovery & Management

class IoTDeviceManager {
    
    private let httpClient: HTTPClient
    
    init(httpClient: HTTPClient = .shared) {
        self.httpClient = httpClient
    }
    
    /// Scan a range of local IPs for IoT devices
    func scanLocalNetwork(
        subnet: String = "192.168.1",
        startIP: Int = 1,
        endIP: Int = 254,
        port: Int? = nil,
        path: String = "/status"
    ) async -> [DiscoveredDevice] {
        var discoveredDevices: [DiscoveredDevice] = []
        
        await withTaskGroup(of: DiscoveredDevice?.self) { group in
            for i in startIP...endIP {
                let ip = "\(subnet).\(i)"
                group.addTask {
                    let endpoint = EndpointType.localDevice(ipAddress: ip, port: port)
                    do {
                        let response: NetworkResponse<DeviceStatusResponse> = try await self.httpClient.request(
                            endpoint: endpoint,
                            path: path,
                            method: .GET,
                            timeoutInterval: 2
                        )
                        return DiscoveredDevice(
                            ipAddress: ip,
                            port: port,
                            name: response.data.deviceName,
                            model: response.data.model,
                            firmwareVersion: response.data.firmwareVersion,
                            isOnline: true
                        )
                    } catch {
                        return nil
                    }
                }
            }
            
            for await device in group {
                if let device = device {
                    discoveredDevices.append(device)
                }
            }
        }
        
        return discoveredDevices
    }
    
    /// Send a command to a local IoT device
    func sendCommand(
        to device: DiscoveredDevice,
        command: DeviceCommand
    ) async throws -> DeviceCommandResponse {
        let endpoint = EndpointType.localDevice(ipAddress: device.ipAddress, port: device.port)
        let response: NetworkResponse<DeviceCommandResponse> = try await httpClient.request(
            endpoint: endpoint,
            path: "/api/command",
            method: .POST,
            body: command,
            timeoutInterval: 5
        )
        return response.data
    }
    
    /// Get device status
    func getDeviceStatus(device: DiscoveredDevice) async throws -> DeviceStatusResponse {
        let endpoint = EndpointType.localDevice(ipAddress: device.ipAddress, port: device.port)
        let response: NetworkResponse<DeviceStatusResponse> = try await httpClient.request(
            endpoint: endpoint,
            path: "/status",
            method: .GET,
            timeoutInterval: 5
        )
        return response.data
    }
}

// MARK: - Cloud API Service

class CloudAPIService {
    
    private let httpClient: HTTPClient
    
    init(httpClient: HTTPClient = .shared) {
        self.httpClient = httpClient
    }
    
    /// Authenticate with the cloud API
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        let response: NetworkResponse<AuthResponse> = try await httpClient.request(
            endpoint: .cloudAPI,
            path: "/v1/auth/login",
            method: .POST,
            body: body
        )
        httpClient.setAuthToken(response.data.accessToken)
        return response.data
    }
    
    /// Register a device with the cloud
    func registerDevice(_ device: DeviceRegistration) async throws -> DeviceRegistrationResponse {
        let response: NetworkResponse<DeviceRegistrationResponse> = try await httpClient.request(
            endpoint: .cloudAPI,
            path: "/v1/devices",
            method: .POST,
            body: device
        )
        return response.data
    }
    
    /// Get all registered devices
    func getRegisteredDevices() async throws -> [RegisteredDevice] {
        let response: NetworkResponse<DeviceListResponse> = try await httpClient.request(
            endpoint: .cloudAPI,
            path: "/v1/devices",
            method: .GET
        )
        return response.data.devices
    }
    
    /// Send device telemetry to cloud
    func sendTelemetry(deviceId: String, telemetry: DeviceTelemetry) async throws {
        let _: NetworkResponse<EmptyResponse> = try await httpClient.request(
            endpoint: .cloudAPI,
            path: "/v1/devices/\(deviceId)/telemetry",
            method: .POST,
            body: telemetry
        )
    }
    
    /// Get firmware update info
    func checkFirmwareUpdate(deviceModel: String, currentVersion: String) async throws -> FirmwareUpdateResponse {
        let response: NetworkResponse<FirmwareUpdateResponse> = try await httpClient.request(
            endpoint: .cloudAPI,
            path: "/v1/firmware/check",
            method: .GET,
            queryParameters: [
                "model": deviceModel,
                "current_version": currentVersion
            ]
        )
        return response.data
    }
    
    /// Download firmware binary
    func downloadFirmware(url: String) async throws -> Data {
        guard let firmwareURL = URL(string: url) else {
            throw NetworkError.invalidURL
        }
        
        let response = try await httpClient.requestRaw(
            endpoint: .cloudAPI,
            path: firmwareURL.path,
            method: .GET,
            headers: ["Accept": "application/octet-stream"],
            timeoutInterval: 120
        )
        return response.data
    }
}

// MARK: - Data Models

struct DiscoveredDevice: Codable, Identifiable {
    var id: String { ipAddress }
    let ipAddress: String
    let port: Int?
    let name: String
    let model: String
    let firmwareVersion: String
    let isOnline: Bool
}

struct DeviceStatusResponse: Codable {
    let deviceName: String
    let model: String
    let firmwareVersion: String
    let uptime: Int
    let temperature: Double?
    let humidity: Double?
    let wifiSignalStrength: Int?
    let freeMemory: Int?
    let status: String
}

struct DeviceCommand: Codable {
    let action: String
    let parameters: [String: AnyCodableValue]?
}

struct DeviceCommandResponse: Codable {
    let success: Bool
    let message: String
    let result: [String: AnyCodableValue]?
}

struct LoginRequest: Codable {
    let email: String
    let password: String
}

struct AuthResponse: Codable {
    let accessToken: String
    let refreshToken: String
    let expiresIn: Int
    let userId: String
}

struct DeviceRegistration: Codable {
    let name: String
    let model: String
    let macAddress: String
    let firmwareVersion: String
    let localIpAddress: String
}

struct DeviceRegistrationResponse: Codable {
    let deviceId: String
    let apiKey: String
    let registeredAt: Date
}

struct RegisteredDevice: Codable, Identifiable {
    let id: String
    let name: String
    let model: String
    let macAddress: String
    let firmwareVersion: String
    let lastSeen: Date?
    let isOnline: Bool
}

struct DeviceListResponse: Codable {
    let devices: [RegisteredDevice]
    let totalCount: Int
}

struct DeviceTelemetry: Codable {
    let timestamp: Date
    let metrics: [String: Double]
    let events: [String]?
}

struct FirmwareUpdateResponse: Codable {
    let updateAvailable: Bool
    let latestVersion: String?
    let downloadUrl: String?
    let releaseNotes: String?
    let fileSize: Int?
}

struct EmptyResponse: Codable {}

// MARK: - AnyCodableValue for flexible JSON

enum AnyCodableValue: Codable {
    case string(String)
    case int(Int)
    case double(Double)
    case bool(Bool)
    case null
    
    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let value = try? container.decode(Bool.self) {
            self = .bool(value)
        } else if let value = try? container.decode(Int.self) {
            self = .int(value)
        } else if let value = try? container.decode(Double.self) {
            self = .double(value)
        } else if let value = try? container.decode(String.self) {
            self = .string(value)
        } else if container.decodeNil() {
            self = .null
        } else {
            throw DecodingError.typeMismatch(
                AnyCodableValue.self,
                DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Unsupported type")
            )
        }
    }
    
    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .string(let value): try container.encode(value)
        case .int(let value): try container.encode(value)
        case .double(let value): try container.encode(value)
        case .bool(let value): try container.encode(value)
        case .null: try container.encodeNil()
        }
    }
}

// MARK: - Usage Example / App Entry Point

import SwiftUI

@main
struct IoTClientApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

struct ContentView: View {
    @StateObject private var viewModel = DeviceViewModel()
    
    var body: some View {
        NavigationView {
            VStack {
                if viewModel.isScanning {
                    ProgressView("Scanning network...")
                        .padding()
                }
                
                List {
                    Section("Discovered Devices") {
                        ForEach(viewModel.discoveredDevices) { device in
                            VStack(alignment: .leading, spacing: 4) {
                                Text(device.name)
                                    .font(.headline)
                                Text("\(device.ipAddress) - \(device.model)")
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                                Text("Firmware: \(device.firmwareVersion)")
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                            .padding(.vertical, 4)
                        }
                    }
                    
                    if let error = viewModel.errorMessage {
                        Section("Errors") {
                            Text(error)
                                .foregroundColor(.red)
                                .font(.caption)
                        }
                    }
                }
                
                HStack(spacing: 16) {
                    Button("Scan Network") {
                        Task {
                            await viewModel.scanNetwork()
                        }
                    }
                    .buttonStyle(.borderedProminent)
                    
                    Button("Cloud Sync") {
                        Task {
                            await viewModel.syncWithCloud()
                        }
                    }
                    .buttonStyle(.bordered)
                }
                .padding()
            }
            .navigationTitle("IoT Client")
        }
    }
}

@MainActor
class DeviceViewModel: ObservableObject {
    @Published var discoveredDevices: [DiscoveredDevice] = []
    @Published var isScanning = false
    @Published var errorMessage: String?
    
    private let deviceManager = IoTDeviceManager()
    private let cloudService = CloudAPIService()
    
    func scanNetwork() async {
        isScanning = true
        errorMessage = nil
        
        let devices = await deviceManager.scanLocalNetwork(
            subnet: "192.168.1",
            startIP: 1,
            endIP: 254
        )
        
        discoveredDevices = devices
        isScanning = false
        
        if devices.isEmpty {
            errorMessage = "No devices found on the local network."
        }
    }
    
    func syncWithCloud() async {
        errorMessage = nil
        
        do {
            // Login to cloud API
            let auth = try await cloudService.login(
                email: "user@example.com",
                password: "password"
            )
            print("Authenticated: \(auth.userId)")
            
            // Register discovered devices
            for device in discoveredDevices {
                let registration = DeviceRegistration(
                    name: device.name,
                    model: device.model,
                    macAddress: "unknown",
                    firmwareVersion: device.firmwareVersion,
                    localIpAddress: device.ipAddress
                )
                
                let result = try await cloudService.registerDevice(registration)
                print("Registered device: \(result.deviceId)")
                
                // Check for firmware updates
                let update = try await cloudService.checkFirmwareUpdate(
                    deviceModel: device.model,
                    currentVersion: device.firmwareVersion
                )
                
                if update.updateAvailable, let version = update.latestVersion {
                    print("Update available for \(device.name): \(version)")
                }
            }
        } catch {
            errorMessage = error.localizedDescription
        }
    }
    
    func sendCommandToDevice(_ device: DiscoveredDevice, action: String) async {
        do {
            let command = DeviceCommand(action: action, parameters: nil)
            let response = try await deviceManager.sendCommand(to: device, command: command)
            print("Command result: \(response.message)")
        } catch {
            errorMessage = "Failed to send command: \(error.localizedDescription)"
        }
    }
}